qry:select.qry:xquery:
for $r in sql(' SELECT PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.e_numero_legajo {%= ','+$AUX/@col_where+' as gb' %}
FROM LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CONC_LIQ_PER, LIQ97_PERSONAL_EMP, PER02_PERSONAL_EMP, LIQ96_CONCEPTOS, LIQ12_TIPOS_CONC {%? (#PARAMIN:@c_agrupacion='centro') {% ,(select P.oi_per_emp_ddo, iifisnull(D.c_centro_costo, P.c_centro_costo_ult) as cc, iifisnull(D.n_p_distrib, 1) as por from liq97_personal_emp as P, liq97_distrib_cos as D join P.oi_per_emp_ddo left outer D.oi_per_emp_ddo ) as DisCC %} {% %} %}
JOIN LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo, LIQ97_PERSONAL_EMP.e_numero_legajo INNER PER02_PERSONAL_EMP.e_numero_legajo, LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto {%? (#PARAMIN:@c_agrupacion='centro') {% ,DisCC.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo %} {% %} %}
WHERE LIQ20_CONC_LIQ_PER.n_valor != 0.0 AND LIQ99_LIQUIDACION.c_estado = \'F\' AND PER02_PERSONAL_EMP.oi_empresa = {%=#PARAMIN:@oi_empresa %} AND LIQ96_CONCEPTOS.c_tipo_concepto in (0,1,2,3,4,6,7,8) AND LIQ19_EJECUCIONES.oi_liquidacion in ({%=string(#LIQUIDACIONES:ROW/@values) %}) {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (#PARAMIN:@cod_desde!='') {% AND LIQ96_CONCEPTOS.c_concepto >= {#PARAMIN:@cod_desde} %} {% %} %} {%? (#PARAMIN:@cod_hasta!='') {% AND LIQ96_CONCEPTOS.c_concepto <= {#PARAMIN:@cod_hasta} %} {% %} %}
GROUP BY PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.e_numero_legajo {%=iif(#AUX:@col_groupby!='', ','+#AUX:@col_groupby,'') %}
{%=iif(#AUX:@col_groupby!='', 'ORDER BY gb ASC','') %}
')/ROWS/ROW,
$l in split('1;{%=string(#LEGAJOS:ROW/@values) %}')/ROWS/ROW join $l/@value INNER $r/@oi_personal_emp orderby $r/@gb ASC

for $r in sql(' SELECT LIQ99_LIQUIDACION.e_periodo, LIQ96_CONCEPTOS.c_tipo_concepto, sum(LIQ20_CONC_LIQ_PER.n_cantidad) as n_cantidad, {%? (#PARAMIN:@c_agrupacion='centro') {% sum(LIQ20_CONC_LIQ_PER.n_valor*DisCC.por) as n_valor %} {% sum(LIQ20_CONC_LIQ_PER.n_valor) as n_valor %} %}
FROM LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ97_PERSONAL_EMP, LIQ12_TIPOS_CONC {%? (#PARAMIN:@c_agrupacion='centro') {% ,(select P.oi_per_emp_ddo, iifisnull(D.c_centro_costo, P.c_centro_costo_ult) as cc, iifisnull(D.n_p_distrib, 1) as por from liq97_personal_emp as P, liq97_distrib_cos as D join P.oi_per_emp_ddo left outer D.oi_per_emp_ddo ) as DisCC %} {% %} %}
JOIN LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo, LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto {%? (#PARAMIN:@c_agrupacion='centro') {% ,DisCC.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo %} {% %} %}
WHERE LIQ20_CONC_LIQ_PER.n_valor != 0.0 AND LIQ99_LIQUIDACION.c_estado = \'F\' AND LIQ96_CONCEPTOS.c_tipo_concepto in (0,1,2,3,4,6,7,8) AND LIQ19_EJECUCIONES.oi_liquidacion in ({%=#PARAMIN:@oi_liqs %}) AND LIQ97_PERSONAL_EMP.e_numero_legajo in ({%=#SOURCE:@value %}) {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (#PARAMIN:@cod_desde!='') {% AND LIQ96_CONCEPTOS.c_concepto >= {#PARAMIN:@cod_desde} %} {% %} %} {%? (#PARAMIN:@cod_hasta!='') {% AND LIQ96_CONCEPTOS.c_concepto <= {#PARAMIN:@cod_hasta} %} {% %} %} {%? (#PARAMIN:@c_agrupacion='centro') {% AND DisCC.cc = {#PARAMIN:@c_centro_costo} %} {% %} %} {%?(#PARAMIN:@col_where!='') {% AND {%=$PARAMIN/@col_where%} = {$PARAMIN/@gb} %} {% %} %}
GROUP BY LIQ99_LIQUIDACION.e_periodo, LIQ96_CONCEPTOS.c_tipo_concepto ORDER BY e_periodo ASC ')/ROWS/ROW, $l in $conceptos/CONC JOIN $l/@e_periodo INNER $r/@e_periodo

for $r in sql(' SELECT LIQ99_LIQUIDACION.e_periodo, LIQ96_CONCEPTOS.c_tipo_concepto, LIQ97_PERSONAL_EMP.e_numero_legajo, LIQ97_PERSONAL_EMP.d_ape_y_nom, {%? (#PARAMIN:@c_agrupacion='centro') {% sum(LIQ20_CONC_LIQ_PER.n_valor*DisCC.por) as n_valor %} {% sum(LIQ20_CONC_LIQ_PER.n_valor) as n_valor %} %}
FROM LIQ19_EJECUCIONES, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ97_PERSONAL_EMP, LIQ12_TIPOS_CONC {%? (#PARAMIN:@c_agrupacion='centro') {% ,(select P.oi_per_emp_ddo, iifisnull(D.c_centro_costo, P.c_centro_costo_ult) as cc, iifisnull(D.n_p_distrib, 1) as por from liq97_personal_emp as P, liq97_distrib_cos as D join P.oi_per_emp_ddo left outer D.oi_per_emp_ddo ) as DisCC %} {% %} %}
JOIN LIQ19_EJECUCIONES.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ99_RECIBOS.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo, LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto {%? (#PARAMIN:@c_agrupacion='centro') {% ,DisCC.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo %} {% %} %}
WHERE LIQ20_CONC_LIQ_PER.n_valor != 0.0 AND LIQ99_LIQUIDACION.c_estado = \'F\' AND LIQ96_CONCEPTOS.c_tipo_concepto in (0,1,2,3,4,6,7,8) AND LIQ19_EJECUCIONES.oi_liquidacion in ({%=#PARAMIN:@oi_liqs %}) AND LIQ97_PERSONAL_EMP.e_numero_legajo in ({%=#SOURCE:@value %}) {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (#PARAMIN:@cod_desde!='') {% AND LIQ96_CONCEPTOS.c_concepto >= {#PARAMIN:@cod_desde} %} {% %} %} {%? (#PARAMIN:@cod_hasta!='') {% AND LIQ96_CONCEPTOS.c_concepto <= {#PARAMIN:@cod_hasta} %} {% %} %} {%? (#PARAMIN:@c_agrupacion='centro') {% AND DisCC.cc = {#PARAMIN:@c_centro_costo} %} {% %} %} {%?(#PARAMIN:@col_where!='') {% AND {%=$PARAMIN/@col_where%} = {$PARAMIN/@gb} %} {% %} %}
GROUP BY LIQ99_LIQUIDACION.e_periodo, LIQ96_CONCEPTOS.c_tipo_concepto, LIQ97_PERSONAL_EMP.e_numero_legajo, LIQ97_PERSONAL_EMP.d_ape_y_nom
ORDER BY e_periodo ASC, e_numero_legajo ASC ')/ROWS/ROW
